import boto3
import os
import logging
from urllib.parse import unquote_plus

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Environment variables (set in Lambda configuration)
OUTPUT_BUCKET_NAME = os.environ.get('OUTPUT_BUCKET_NAME')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN')

def lambda_handler(event, context):
    logger.info(f"Received event: {event}")

    for record in event['Records']:
        # Extract S3 event details
        bucket_name = record['s3']['bucket']['name']
        key = unquote_plus(record['s3']['object']['key'])
        
        logger.info(f"Processing object: s3://{bucket_name}/{key}")

        try:
            # 1. Read from S3
            response = s3_client.get_object(Bucket=bucket_name, Key=key)
            image_content = response['Body'].read()
            logger.info(f"Successfully read image content from {key}. Size: {len(image_content)} bytes")

            # --- Placeholder for image processing logic ---
            # In a real application, you would perform image manipulation here.
            # For this example, we'll just prepend a string and save it as text.
            processed_content = f"Processed image from {key}:\n{image_content.decode('utf-8', errors='ignore')}"
            processed_filename = f"processed-{os.path.basename(key)}.txt"
            # --- End Placeholder ---

            # 2. Write results back to S3
            if not OUTPUT_BUCKET_NAME:
                logger.error("OUTPUT_BUCKET_NAME environment variable is not set.")
                raise ValueError("Output S3 bucket name is not configured.")

            s3_client.put_object(
                Bucket=OUTPUT_BUCKET_NAME,
                Key=processed_filename,
                Body=processed_content.encode('utf-8')
            )
            logger.info(f"Successfully wrote processed content to s3://{OUTPUT_BUCKET_NAME}/{processed_filename}")

            # 3. Send notifications via SNS
            if not SNS_TOPIC_ARN:
                logger.warning("SNS_TOPIC_ARN environment variable is not set. Skipping SNS notification.")
            else:
                message = {
                    "source_bucket": bucket_name,
                    "source_key": key,
                    "processed_bucket": OUTPUT_BUCKET_NAME,
                    "processed_key": processed_filename,
                    "status": "SUCCESS",
                    "message": "Image processing completed successfully."
                }
                sns_client.publish(
                    TopicArn=SNS_TOPIC_ARN,
                    Message=str(message), # SNS expects string message
                    Subject=f"Image Processed: {key}"
                )
                logger.info(f"Successfully published SNS notification to {SNS_TOPIC_ARN}")

        except Exception as e:
            logger.error(f"Error processing s3://{bucket_name}/{key}: {e}", exc_info=True)
            # Optionally send a failure notification
            if SNS_TOPIC_ARN:
                error_message = {
                    "source_bucket": bucket_name,
                    "source_key": key,
                    "status": "FAILED",
                    "error": str(e)
                }
                try:
                    sns_client.publish(
                        TopicArn=SNS_TOPIC_ARN,
                        Message=str(error_message),
                        Subject=f"Image Processing FAILED: {key}"
                    )
                    logger.info(f"Published SNS failure notification for {key}")
                except Exception as sns_e:
                    logger.error(f"Failed to publish SNS failure notification: {sns_e}", exc_info=True)

    return {
        'statusCode': 200,
        'body': 'Image processing initiated for all records.'
    }